Method.Source:
public void insert()
{
    next insert();

    if (BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGDMSRevereIntegrationEventClass)))
    {
        str taxRegistrationType;
        taxRegistrationType = TaxRegistrationType::find(this.TaxRegistrationType).TaxRegstrationType;
        str descriptiveKeyCollection =strFmt("RegistrationType='%1',CountryRegionId='%2'",taxRegistrationType,this.CountryRegionId);

        ETGDMSRevereIntegrationContract contract = new ETGDMSRevereIntegrationContract();

        contract.parmPrimaryKeyCollection(descriptiveKeyCollection);
        contract.parmPrimaryCollectionName("RegistrationTypes");
        contract.parmoperationType("Insert");

        ETGDMSRevereIntegrationEventClass eventClass = ETGDMSRevereIntegrationEventClass::newFromContract(contract);
        eventClass.send();
    }
}

public void update()
{
    TaxRegistrationTypeApplicabilityRule origRule = this.orig();

    str oldCountryRegionId = origRule.CountryRegionId;

    next update();

    if (BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGDMSRevereIntegrationEventClass)))
    {
        str oldCountryValue =
            (this.CountryRegionId != oldCountryRegionId)
            ? oldCountryRegionId
            : this.CountryRegionId;

        str newRegistrationValue =
            TaxRegistrationType::find(this.TaxRegistrationType).TaxRegstrationType;

        str oldRegistrationValue =
            ETGRegistrationTypeCache::getOldValue(this.TaxRegistrationType);

        if (oldRegistrationValue == "")
        {
            oldRegistrationValue = newRegistrationValue;
        }

        str descriptiveKeyCollection =
            strFmt("RegistrationType='%1',CountryRegionId='%2',CountryRegionIdOld='%3',RegistrationTypeOld='%4'",
                newRegistrationValue,
                this.CountryRegionId,
                oldCountryValue,
                oldRegistrationValue);

        ETGDMSRevereIntegrationContract contract = new ETGDMSRevereIntegrationContract();
        contract.parmPrimaryKeyCollection(descriptiveKeyCollection);
        contract.parmPrimaryCollectionName("RegistrationTypes");
        contract.parmoperationType("Update");

        ETGDMSRevereIntegrationEventClass eventClass =
        ETGDMSRevereIntegrationEventClass::newFromContract(contract);

        eventClass.send();

        ETGRegistrationTypeCache::clear(this.TaxRegistrationType);
    }
}
